    def test_structured_plan_normalizes_modules_changes_and_questions(self) -> None:
        structured = _ai_build_structured_plan(
            {
                "required_questions": ["Confirm this plan or tell me what to change."],
                "required_question_meta": {"id": "confirm_plan", "kind": "confirm_plan"},
                "assumptions": ["Use the existing Contacts form."],
                "risk_flags": ["Review downstream automations before apply."],
                "affected_artifacts": [
                    {"artifact_type": "module", "artifact_id": "contacts"},
                ],
                "proposed_changes": [
                    {
                        "op": "add_field",
                        "artifact_type": "module",
                        "artifact_id": "contacts",
                        "field": {"label": "Level notes", "type": "text"},
                    }
                ],
                "planner_state": {"intent": "add_field"},
            },
            {
                "full_selected_artifacts": [
                    {"artifact_type": "module", "artifact_id": "contacts", "manifest": {"module": {"name": "Contacts"}}},
                ],
            },
        )

        self.assertEqual(structured["intent"], "add_field")
        self.assertEqual(structured["version"], "1")
        self.assertEqual(structured["summary"], "Add a new field 'Level notes' to Contacts.")
        self.assertEqual(
            structured["modules"],
            [{"module_id": "contacts", "module_label": "Contacts", "status": "planned"}],
        )
        self.assertEqual(structured["changes"][0]["op"], "add_field")
        self.assertEqual(structured["changes"][0]["module_id"], "contacts")
        self.assertEqual(structured["changes"][0]["summary"], "Add field 'Level notes' (text) in Contacts.")
        self.assertEqual(
            structured["sections"],
            [
                {
                    "key": "fields",
                    "title": "Fields",
                    "items": ["Contacts: add 'Level notes' as a text field."],
                },
                {
                    "key": "sandbox_checks",
                    "title": "What to check in sandbox",
                    "items": ["Open Contacts and look for the 'Level notes' field on the affected form or view."],
                },
            ],
        )
        self.assertEqual(
            structured["requested_scope"],
            {"requested_modules": [], "missing_modules": [], "requested_artifacts": ["Contacts"]},
        )
        self.assertEqual(
            structured["clarifications"],
            {
                "items": ["Confirm this plan or tell me what to change."],
                "meta": {
                    "id": "confirm_plan",
                    "kind": "confirm_plan",
                    "prompt": "Confirm this plan or tell me what to change.",
                },
            },
        )
        self.assertEqual(structured["questions"]["meta"]["id"], "confirm_plan")
        self.assertEqual(structured["assumptions"], ["Use the existing Contacts form."])
        self.assertEqual(structured["risks"], ["Review downstream automations before apply."])

    def test_structured_plan_tracks_non_module_artifacts_as_first_class_scope(self) -> None:
        structured = _ai_build_structured_plan(
            {
                "affected_artifacts": [
                    {"artifact_type": "automation", "artifact_id": "automation_quote_reminder"},
                    {"artifact_type": "email_template", "artifact_id": "email_quote_approved"},
                ],
                "proposed_changes": [
                    {
                        "op": "update_automation_record",
                        "artifact_type": "automation",
                        "artifact_id": "automation_quote_reminder",
                        "automation": {
                            "name": "Quote Reminder",
                            "trigger": {"kind": "event"},
                            "steps": [{"kind": "action", "action_id": "system.send_email"}],
                        },
                    },
                    {
                        "op": "update_email_template_record",
                        "artifact_type": "email_template",
                        "artifact_id": "email_quote_approved",
                        "email_template": {
                            "name": "Quote Approved",
                            "subject": "Quote approved",
                            "body_html": "<p>Approved</p>",
                            "body_text": "Approved",
                        },
                    },
                ],
                "planner_state": {"intent": "multi_request"},
            },
            {
                "full_selected_artifacts": [
                    {"artifact_type": "automation", "artifact_id": "automation_quote_reminder", "manifest": {"name": "Quote Reminder"}},
                    {"artifact_type": "email_template", "artifact_id": "email_quote_approved", "manifest": {"name": "Quote Approved"}},
                ],
                "request_summary": "Update the reminder automation and quote approved email.",
            },
        )

        self.assertEqual(
            structured["artifacts"],
            [
                {
                    "artifact_type": "automation",
                    "artifact_id": "automation_quote_reminder",
                    "artifact_label": "Quote Reminder",
                    "status": "planned",
                },
                {
                    "artifact_type": "email_template",
                    "artifact_id": "email_quote_approved",
                    "artifact_label": "Quote Approved",
                    "status": "planned",
                },
            ],
        )
        self.assertEqual(
            structured["requested_scope"],
            {
                "requested_modules": [],
                "missing_modules": [],
                "requested_artifacts": ["Quote Reminder", "Quote Approved"],
            },
        )
        self.assertEqual(structured["changes"][0]["artifact_type"], "automation")
        self.assertEqual(structured["changes"][0]["artifact_label"], "Quote Reminder")
        self.assertEqual(structured["changes"][1]["artifact_type"], "email_template")
        self.assertEqual(structured["changes"][1]["artifact_label"], "Quote Approved")

